VALUES
  ('cpa-moex-00831', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '不論控制風險評估水準之高低，查核人員均須執行下列何項程序？', '["執行控制測試，以決定內部控制之有效性", "執行證實程序，將重要交易之偵查風險控制在可接受之程度內", "執行內部控制問卷，驗證內部控制是否有效", "出具致管理階層函"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00832', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依我國審計準則公報第66號「書面聲明」規定，下列敘述何者錯誤？', '["如代表受查者簽署委任書之人員不再承擔攸關責任，查核人員可能要求管理階層於書面聲 明中再次確認對查核案件條款所述責任之認知與瞭解時，可採用「就本公司所知」之限制 性文字", "為所要求書面聲明之目的，查核人員可與管理階層溝通顯然微小門檻", "管理階層修改查核人員所要求書面聲明之內容，並不表示管理階層未提供書面聲明，惟修 改之原因可能影響查核意見", "管理階層之意圖對投資之評價基礎係屬重要時，查核人員如無法自管理階層取得有關其意 圖之書面聲明，則將無法取得足夠及適切之查核證據"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00833', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員於判斷是否已取得足夠及適切之查核證據時，下列何項並非應考量之因素？', '["查核報告之類型", "財務報導之及時性", "成本與效益之權衡", "查核程序之性質"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00834', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員認為使用金額區間估計以評估管理階層單一金額估計之合理性係屬適當時，該金額 區間應包括所有合理之結果而非所有可能之結果。若該金額區間包括所有可能之結果，則該 金額區間會因太大而降低其有用性，致無法達成查核之目的。因此就評估管理階層單一金額 估計之合理性而言，查核人員宜將金額區間縮小至不超過下列何者？', '["財務報表整體重大性", "所設定顯然微小之門檻", "會計估計帳載金額", "執行重大性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00835', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員於執行應收帳款控制測試，以確認應收帳款授信額度是否經適當人員核准。查核樣 本量為40，計算的偏差率上限設為5%。如在前10筆樣本中已發現8筆未經適當人員核准 ，此時查核人員最可能之因應方式為何？', '["繼續其他30筆樣本的測試", "重新計算樣本量大小", "增加可接受的偏差比率", "停止測試，重新設定應收帳款的控制風險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00836', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關核閱財務報表所執行程序的敘述，下列何者錯誤？', '["核閱人員應向管理階層查詢截至財務報表日所發生可能須於財務報表中調整或揭露之事 項是否均已辨認", "核閱人員所執行之程序通常限於查詢（主要向受核閱者負責財務與會計事務之人員查詢） 、分析性程序及其他核閱程序", "核閱人員通常無須驗證管理階層對有關訴訟或索賠之查詢所作之回應，因此無須函詢受核 閱者之律師", "核閱人員仍應向管理階層取得書面聲明"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00837', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何項為影響一般用途整體財務報表重大性的最主要因素？', '["查核人員的風險評估", "過去年度查核不實表達的程度", "財務報表一般使用者之經濟決策需求", "受查者同業過去三年常用的重大性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00838', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依照我國審計準則公報第 43 號之規定，查核人員為因應管理階層踰越控制之查核程序，而 複核可能導致重大不實表達之會計估計，其主要目的為何？', '["確定是否有跡象顯示管理階層所做之判斷及假設存有偏差", "懷疑查核人員基於當時取得資訊所做之專業判斷的正確性", "確定財務報表認列或揭露之公允價值會計估計是否合理", "判斷是否已有辨認出之會計估計因具高度估計不確定性而導致顯著風險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00839', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '甲公司設置有完善的內部稽核部門且直接向財務長報告。該公司之內部稽核報告顯示，內部控 制皆依設計目的執行並能產生可靠之會計紀錄。依據前述，該公司之簽證會計師應如何因應？', '["可以不要再執行內部控制測試", "可以加強管理控制之瞭解與評估的深度", "避免重複內部稽核已經執行過的測試工作", "對於內部稽核所執行之測試給予有限度的信賴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00840', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '甲公司持有乙公司的80%之流通在外普通股，而對乙公司具有控制力，並另持有丙公司發行 之公司債總額的50%。甲、乙、丙三家公司的財務報表分別委託子、丑、寅三位會計師進行 查核。丑會計師為集團查核目的而對乙公司的財務報表執行查核工作，子會計師採用丑會計 師之查核工作，並經取得足夠及適切的查核證據後，認為該集團財務報表業已允當表達。下 列有關集團財務報表查核之敘述，何者錯誤？', '["子會計師應對集團之組成個體（乙公司）決定是否為其查核人員（丑會計師）之工作承擔責任", "若子會計師決定為丑會計師之工作承擔責任，則必須參與丑會計師之工作達可對集團財務 報表表示意見之程度，且不得於集團查核報告中提及丑會計師對乙公司財務報表之查核", "若子會計師決定不為丑會計師之工作承擔責任，應於集團查核報告中增列其他事項段提及 丑會計師之姓名及其對乙公司財務報表之查核", "無論集團查核報告是否提及組成個體查核人員之查核，集團查核意見均應由集團主辦會計 師（子會計師）負責"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
